export declare const GOODS_RECEIPT_NOTE_HTML =
  '<!DOCTYPE html>\n<html lang="en">\n<head>\n  <meta charset="UTF-8" />\n  <title>Goods Received Note {{document.number}}</title>\n  <style>\n    /* GRN-specific overrides */\n    .grn-details {\n      display: flex;\n      justify-content: space-between;\n      align-items: flex-start;\n      margin-bottom: 20px;\n    }\n    .grn-details .left {\n      flex: 1;\n    }\n    .grn-details .right {\n      flex: 0 0 auto;\n    }\n    .grn-items-table {\n      width: 100%;\n      border-collapse: collapse;\n      margin-bottom: 16px;\n    }\n    .grn-items-table thead th {\n      background: #f0f0f0;\n      font-size: 10px;\n      font-weight: 700;\n      text-transform: uppercase;\n      color: #555;\n      padding: 8px 6px;\n      border-bottom: 2px solid #ccc;\n      text-align: left;\n    }\n    .grn-items-table thead th.text-right {\n      text-align: right;\n    }\n    .grn-items-table thead th.text-center {\n      text-align: center;\n    }\n    .grn-items-table tbody td {\n      padding: 6px;\n      border-bottom: 1px solid #e5e5e5;\n      font-size: 11px;\n      vertical-align: top;\n    }\n    .grn-items-table tbody td.text-right {\n      text-align: right;\n    }\n    .grn-items-table tbody td.text-center {\n      text-align: center;\n    }\n    .grn-items-table tbody tr:nth-child(even) {\n      background: #f9f9f9;\n    }\n    .variance-positive {\n      color: #b91c1c;\n      font-weight: 600;\n    }\n    .variance-zero {\n      color: #15803d;\n    }\n    .inspection-notes {\n      margin-bottom: 16px;\n      padding: 12px;\n      border: 1px solid #ccc;\n      border-radius: 4px;\n      min-height: 60px;\n    }\n    .inspection-notes .section-title {\n      font-size: 10px;\n      font-weight: 700;\n      text-transform: uppercase;\n      color: #888;\n      margin-bottom: 8px;\n    }\n    .condition-notes {\n      margin-bottom: 16px;\n      padding: 12px;\n      border: 1px solid #ccc;\n      border-radius: 4px;\n      min-height: 60px;\n    }\n    .condition-notes .section-title {\n      font-size: 10px;\n      font-weight: 700;\n      text-transform: uppercase;\n      color: #888;\n      margin-bottom: 8px;\n    }\n  </style>\n</head>\n<body>\n  <div class="page">\n\n    \n<div class="header">\n  <div class="header-left">\n    {{#if branding.showLogo}}\n    {{#if company.logoUrl}}\n    <div class="logo-section">\n      <img src="{{company.logoUrl}}" alt="{{company.name}} logo" />\n    </div>\n    {{/if}}\n    {{/if}}\n    <div class="company-name">{{company.name}}</div>\n    {{#if company.legalName}}\n    <div class="company-legal-name">{{company.legalName}}</div>\n    {{/if}}\n  </div>\n  <div class="header-right">\n    <div class="company-details">\n      <p style="white-space:pre-line">{{company.address}}</p>\n      {{#if company.phone}}<p>Tel: {{company.phone}}</p>{{/if}}\n      {{#if company.email}}<p>{{company.email}}</p>{{/if}}\n      {{#if company.website}}<p>{{company.website}}</p>{{/if}}\n      {{#if branding.showVatNumber}}\n      {{#if company.vatNumber}}<p class="vat-number">VAT: {{company.vatNumber}}</p>{{/if}}\n      {{/if}}\n      {{#if branding.showCompanyReg}}\n      {{#if company.companyNumber}}<p class="company-reg">Reg: {{company.companyNumber}}</p>{{/if}}\n      {{/if}}\n    </div>\n  </div>\n</div>\n\n    <div class="document-title">Goods Received Note</div>\n\n    <div class="grn-details">\n      <div class="left">\n        <div class="address-block">\n          <div class="label">Supplier</div>\n          <div class="name">{{counterparty.name}}</div>\n          <div class="address">{{counterparty.address}}</div>\n        </div>\n      </div>\n      <div class="right">\n        <div class="document-details">\n          <table>\n            <tr><th>GRN No.</th><td>{{document.number}}</td></tr>\n            <tr><th>Date</th><td>{{formatDate document.date}}</td></tr>\n            {{#if document.reference}}\n            <tr><th>PO Reference</th><td>{{document.reference}}</td></tr>\n            {{/if}}\n            {{#if metadata.supplierReference}}\n            <tr><th>Supplier Del. Note</th><td>{{metadata.supplierReference}}</td></tr>\n            {{/if}}\n          </table>\n        </div>\n      </div>\n    </div>\n\n    <table class="grn-items-table">\n      <thead>\n        <tr>\n          <th style="width:30px">#</th>\n          <th style="width:100px">Item Code</th>\n          <th>Description</th>\n          <th class="text-right" style="width:80px">Ordered</th>\n          <th class="text-right" style="width:80px">Received</th>\n          <th class="text-right" style="width:80px">Variance</th>\n        </tr>\n      </thead>\n      <tbody>\n        {{#each lines}}\n        <tr class="line-item-row">\n          <td>{{this.lineNumber}}</td>\n          <td>{{this.itemCode}}</td>\n          <td>{{this.description}}</td>\n          <td class="text-right">{{formatNumber this.quantity 0}}</td>\n          <td class="text-right">{{formatNumber this.receivedQty 0}}</td>\n          <td class="text-right">{{formatNumber this.variance 0}}</td>\n        </tr>\n        {{/each}}\n      </tbody>\n    </table>\n\n    <div class="inspection-notes">\n      <div class="section-title">Inspection Notes</div>\n      {{#if document.notes}}\n      {{document.notes}}\n      {{/if}}\n    </div>\n\n    <div class="condition-notes">\n      <div class="section-title">Damage / Discrepancy Notes</div>\n    </div>\n\n    <div class="signature-area">\n      <div class="signature-line">\n        <div class="label">Received by:</div>\n        <div class="line"></div>\n      </div>\n      <div class="signature-line">\n        <div class="label">Print name:</div>\n        <div class="line"></div>\n      </div>\n      <div class="signature-line">\n        <div class="label">Date:</div>\n        <div class="line"></div>\n      </div>\n    </div>\n\n    \n<div class="page-footer">\n  {{company.name}} &mdash; Generated by Nexa ERP\n  <div class="page-numbers">Page <span class="pageNumber"></span> of <span class="totalPages"></span></div>\n</div>\n\n  </div>\n</body>\n</html>';
